    void start();
    void stop();

    [[nodiscard]] LinkSnapshot snapshot() const;
    [[nodiscard]] double beatAt(TimePoint timePoint) const;

    void setTempoBpm(double tempoBpm);

    [[nodiscard]] LinkMode mode() const noexcept;
