#include "link/LinkManager.hpp"

#include <chrono>
#include <cmath>
#include <iostream>
#include <stdexcept>
#include <thread>

namespace {

void assertNear(double actual, double expected, double tolerance, const char* message) {
    if (std::fabs(actual - expected) > tolerance) {
        std::cerr << message << " | expected=" << expected << " actual=" << actual << " tolerance=" << tolerance << '\n';
        throw std::runtime_error(message);
    }
}

void assertTrue(bool condition, const char* message) {
    if (!condition) {
        throw std::runtime_error(message);
    }
}

void testSimulationBeatAdvances() {
    xpad::link::LinkManager manager({
        .initialTempoBpm = 120.0,
        .quantum = 4.0,
        .preferAbletonLink = false,
    });

    manager.start();
    const auto first = manager.snapshot();
    std::this_thread::sleep_for(std::chrono::milliseconds(250));
    const auto second = manager.snapshot();

    const double delta = second.beat - first.beat;
    assertNear(delta, 0.5, 0.2, "Beat should advance approximately half a beat in 250ms at 120 BPM");
    manager.stop();
}

void testTempoChangePreservesContinuity() {
    xpad::link::LinkManager manager({
        .initialTempoBpm = 120.0,
        .quantum = 4.0,
        .preferAbletonLink = false,
    });

    manager.start();
    std::this_thread::sleep_for(std::chrono::milliseconds(200));
    const double beatBeforeChange = manager.snapshot().beat;

    manager.setTempoBpm(60.0);
    const double beatImmediatelyAfter = manager.snapshot().beat;
    assertNear(beatImmediatelyAfter, beatBeforeChange, 0.05, "Tempo change should not create a beat discontinuity");

    std::this_thread::sleep_for(std::chrono::milliseconds(300));
    const double beatLater = manager.snapshot().beat;
    assertNear(beatLater - beatImmediatelyAfter, 0.3, 0.15, "Beat progression should follow the new tempo after change");
    manager.stop();
}

void testBeatProjection() {
    xpad::link::LinkManager manager({
        .initialTempoBpm = 120.0,
        .quantum = 4.0,
        .preferAbletonLink = false,
    });

    manager.start();
    std::this_thread::sleep_for(std::chrono::milliseconds(100));
    const auto now = std::chrono::steady_clock::now();
    const double currentBeat = manager.snapshot().beat;
    const double projectedBeat = manager.beatAt(now + std::chrono::milliseconds(500));

    assertNear(projectedBeat - currentBeat, 1.0, 0.15, "Projected beat should be one beat ahead after 500ms at 120 BPM");
    manager.stop();
}

void testModeIsSimulationWhenPreferred() {
    xpad::link::LinkManager manager({
        .initialTempoBpm = 126.0,
        .quantum = 4.0,
        .preferAbletonLink = false,
    });

    manager.start();
    assertTrue(manager.mode() == xpad::link::LinkMode::Simulation, "Manager should remain in simulation mode when requested");
    manager.stop();
}

} // namespace

int main() {
    testSimulationBeatAdvances();
    testTempoChangePreservesContinuity();
    testBeatProjection();
    testModeIsSimulationWhenPreferred();
    std::cout << "All LinkManager tests passed.\n";
    return 0;
}
